cd ~/.openclaw/workspace-main-stock && python3 << 'EOF'
import requests
from datetime import datetime

# Read watchlist
with open('stock/watchlist.txt', 'r', encoding='utf-8') as f:
    lines = f.readlines()

results = []
for line in lines:
    line = line.strip()
    if line and '|' in line:
        parts = line.split('|')
        code = parts[0]
        name = parts[1]

        # For A-shares, use the proper format
        if code.isdigit():
            if code.startswith('6'):
                ts_code = f"1{code}"  # Shanghai
            else:
                ts_code = f"0{code}"  # Shenzhen
        else:
            ts_code = code

        # Try the hq.sinajs.cn API (sina finance)
        if code.isdigit():
            if code.startswith('6'):
                symbol = f"sh{code}"
            else:
                symbol = f"sz{code}"
        elif '.HK' in code:
            symbol = f"hk{code.replace('.HK', '')}"
        else:
            # US stocks
            symbol = f"gb_{code.lower()}"

        url = f"http://hq.sinajs.cn/list={symbol}"
        try:
            resp = requests.get(url, timeout=5, headers={'User-Agent': 'Mozilla/5.0'})
            resp.encoding = 'gbk'
            if resp.status_code == 200 and 'var' in resp.text:
                data = resp.text.strip()
                print(f"{symbol}: {data[:200]}")
            else:
                print(f"{symbol}: No data")
        except Exception as e:
            print(f"{symbol}: Error - {e}")
EOF

